class Solution {
public:
    int wordCount(vector<string>& startWords, vector<string>& targetWords) {
        unordered_set<int> startMasks;
        for (const string& s : startWords) {
            int mask = 0;
            for (char c : s) mask |= 1 << (c - 'a');
            startMasks.insert(mask);
        }
        int ans = 0;
        for (const string& t : targetWords) {
            int mask = 0;
            for (char c : t) mask |= 1 << (c - 'a');
            for (char c : t) {
                int prev = mask ^ (1 << (c - 'a'));
                if (startMasks.count(prev)) {
                    ++ans;
                    break;
                }
            }
        }
        return ans;
    }
};
```
